export class FireworksImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]) {
    const backendConfig = modelToBackendConfig[this.modelId];

    // Handle async models (flux-kontext-*)
    if (backendConfig?.urlFormat === 'workflows_async') {
      return this.doGenerateAsync({ body, headers, abortSignal, ... });
    }

    // Handle sync models - return binary directly
    const { value: response } = await postJsonToApi({
      url: getUrlForModel(this.config.baseURL, this.modelId),
      headers: combinedHeaders,
      body,
      successfulResponseHandler: createBinaryResponseHandler(),
    });

    return { images: [response], warnings, response: { ... } };
  }

  private async doGenerateAsync({...}) {
    // 1. Submit request, get request_id
    const { value: submitResponse } = await postJsonToApi({...});
    const requestId = submitResponse.request_id;

    // 2. Poll for result
    const imageUrl = await this.pollForImageUrl({ requestId, ... });

    // 3. Download image
    const { value: imageBytes } = await getFromApi({ url: imageUrl, ... });

    return { images: [imageBytes], warnings, response: { ... } };
  }

  private async pollForImageUrl({ requestId, ... }): Promise<string> {
    // Poll with configurable intervals and timeout
    for (let i = 0; i < maxPollAttempts; i++) {
      const { value: pollResponse } = await postJsonToApi({...});

      if (pollResponse.status === 'Ready') {
        return pollResponse.result?.sample;
      }

      await delay(pollIntervalMillis);
    }

    throw new Error(`Timeout after ${pollTimeoutMillis}ms`);
  }
}
