import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'This model does not support image editing via `files`.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'This model does not support mask-based image editing.',
      });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const { style, pixelDensity } = pixelArtOptions ?? {};

    // Parse size into width and height
    let width: number | undefined;
    let height: number | undefined;
    if (size != null) {
      const parts = size.split('x');
      if (parts.length === 2) {
        width = parseInt(parts[0], 10);
        height = parseInt(parts[1], 10);
      }
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(width != null ? { width } : {}),
        ...(height != null ? { height } : {}),
        ...(style != null ? { style } : {}),
        ...(pixelDensity != null ? { pixel_density: pixelDensity } : {}),
        response_format: 'b64_json',
      },
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: error => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item =>
        convertBase64ToUint8Array(item.b64_json),
      ),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// limited version of the schema, focussed on what is needed for the implementation
// this approach limits breakages when the API changes and increases efficiency
const pixelArtImageResponseSchema = z.object({
  data: z.array(z.object({ b64_json: z.string() })),
});

const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The visual style of the generated image.
       * - `pixel`: Classic pixel art look with hard edges and limited palette.
       * - `retro`: Retro-inspired aesthetic reminiscent of early home computers.
       * - `8bit`: Pure 8-bit style with strict palette and chunky pixels.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The pixel density (scaling factor) of the generated image.
       * Higher values produce more densely packed pixels.
       * Defaults to 1. Typical range: 1–8.
       */
      pixelDensity: z.number().int().min(1).max(8).nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

