import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==';
const prompt = 'A pixel art landscape with mountains';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generations': {
      response: {
        type: 'json-value',
        body: {
          data: [{ b64_json: TEST_BASE64 }],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('should send the correct request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        width: 512,
        height: 512,
        response_format: 'b64_json',
      });
    });

    it('should pass style and pixelDensity provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'retro', pixelDensity: 4 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        width: 256,
        height: 256,
        style: 'retro',
        pixel_density: 4,
        response_format: 'b64_json',
      });
    });

    it('should pass the 8bit style', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit' },
        },
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ style: '8bit' });
    });

    it('should not include size fields when size is undefined', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('width');
      expect(body).not.toHaveProperty('height');
    });

    it('should decode b64_json response into Uint8Array images', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
    });

    it('should decode multiple b64_json images', async () => {
      server.urls['https://api.example.com/images/generations'].response = {
        type: 'json-value',
        body: {
          data: [
            { b64_json: TEST_BASE64 },
            { b64_json: TEST_BASE64 },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      for (const img of result.images) {
        expect(img).toBeInstanceOf(Uint8Array);
      }
    });

    it('should pass custom headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          'X-Custom-Provider-Header': 'provider-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'X-Custom-Request-Header': 'request-value',
        },
      });

